// Parse incoming webhook request and build cluster_summaries query
const webhookData = $input.first().json;
const requestBody = webhookData.body || {};

const filters = {
  time_window: requestBody.time_window || null,
  category: requestBody.category || null,
  subcategory: requestBody.subcategory || null,
  keywords: requestBody.keywords || [],
  size: requestBody.size || 1000,
  use_cluster_filter: requestBody.use_cluster_filter !== false
};

const options = {
  style_version: requestBody.style_version || "Neutral",
  sentiment_target: requestBody.sentiment_target || "None"
};

// Build query for cluster_summaries to get article_ids
const cluster_must = [];

// Time window filter
if (filters.time_window) {
  const now = new Date();
  let gte;
  switch(filters.time_window.toLowerCase()) {
    case 'last_6_hours':
    case 'last_6h':
      gte = new Date(now.getTime() - 6*60*60*1000);
      break;
    case 'last_12_hours':
    case 'last_12h':
      gte = new Date(now.getTime() - 12*60*60*1000);
      break;
    case 'last_24_hours':
    case 'last_24h':
      gte = new Date(now.getTime() - 24*60*60*1000);
      break;
    case 'last_3_days':
    case 'last_3d':
      gte = new Date(now.getTime() - 3*24*60*60*1000);
      break;
    case 'last_7_days':
    case 'last_7d':
      gte = new Date(now.getTime() - 7*24*60*60*1000);
      break;
    case 'last_30_days':
    case 'last_30d':
      gte = new Date(now.getTime() - 30*24*60*60*1000);
      break;
  }
  if (gte) {
    cluster_must.push({ range: { processed_at: { gte: gte.toISOString() }}});
    console.log(`⏰ Time filter: ${filters.time_window} (from ${gte.toISOString()})`);
  }
}

// Category warning (not supported in cluster_summaries)
if (filters.category) {
  console.log(`⚠️ Category filter "${filters.category}" will be ignored (cluster_summaries has no category field)`);
}

// Subcategory is topic_label in cluster_summaries
if (filters.subcategory) {
  cluster_must.push({ term: { "topic_label.keyword": filters.subcategory }});
  console.log(`🏷️ Topic label filter: ${filters.subcategory}`);
}

// Build the cluster_summaries query
const cluster_query = {
  size: filters.size,
  _source: [
    "article_ids",
    "cluster_id",
    "request_id",
    "topic_label",
    "summary"
  ],
  query: {
    bool: {
      must: cluster_must.length > 0 ? cluster_must : [{ match_all: {} }]
    }
  },
  sort: [
    { processed_at: { order: "desc" }}
  ]
};

console.log(`🔍 Cluster query: ${JSON.stringify(cluster_query, null, 2)}`);

// Return array of objects with json property
return [{
  json: {
    filters: filters,
    options: options,
    use_cluster_filter: filters.category,
    cluster_query: cluster_query
  }
}];

const parseData = $('Parse Webhook Request').first().json;
const useClusterFilter = parseData.use_cluster_filter;

if (!useClusterFilter) {
  console.log('⚠️ Cluster filter disabled, will use direct article filtering');
  return [{ json: { article_ids: null, filters: parseData.filters, options: parseData.options }}];
}

const hits = $json.hits?.hits ?? [];
const allArticleIds = new Set();
const clusterInfo = [];

hits.forEach(hit => {
  const source = hit._source || {};
  // NEW SCHEMA: article_ids is an array at the top level
  const articleIds = source.article_ids || [];

  clusterInfo.push({
    cluster_id: source.cluster_id,
    request_id: source.request_id,
    topic_label: source.topic_label,
    article_count: articleIds.length
  });

  // Add all article IDs to the set
  articleIds.forEach(id => {
    if (id) allArticleIds.add(id);
  });
});

const uniqueIds = Array.from(allArticleIds);
console.log(`📋 Found ${uniqueIds.length} unique article IDs from ${hits.length} clusters`);
console.log(`📊 Cluster info: ${JSON.stringify(clusterInfo.slice(0, 3))}`);

if (uniqueIds.length === 0) {
  console.log('⚠️ No article IDs found in clusters, will use direct article filtering');
  return [{
    json: {
      article_ids: null,
      filters: parseData.filters,
      options: parseData.options,
      cluster_count: 0
    }
  }];
}

return [{
  json: {
    article_ids: uniqueIds,
    filters: parseData.filters,
    options: parseData.options,
    cluster_count: hits.length,
    cluster_info: clusterInfo
  }
}];

const hits = $json.hits?.hits ?? [];

// Check if this was a "no clusters found" case
const buildQueryData = $('Build Articles Query').first().json;
if (buildQueryData?.no_clusters_found) {
  console.log('📭 No clusters found - throwing error for empty result');
  throw new Error('NO_CLUSTERS_FOUND: No clusters matched your search criteria. Try different filters or categories.');
}

if (hits.length === 0) {
  console.log('⚠️ No article summaries found matching the query - throwing error');
  throw new Error('NO_ARTICLES_FOUND: No article summaries found for the selected clusters.');
}

// article_summaries schema: article_id, id, summary, language, processed_at
const summaries = hits.map(h => h._source).filter(s => s && s.summary);

if (summaries.length === 0) {
  console.log('⚠️ No valid summaries (all missing summary text) - throwing error');
  throw new Error('NO_VALID_ARTICLES: Article summaries found but all are missing content.');
}

// Transform to format expected by downstream nodes
// Use summary as "body" for LLM processing
const MAX_SUMMARY_LENGTH = 2000;  // Summaries should already be short

const processed = summaries.map((s, index) => {
  const originalLength = s.summary ? s.summary.length : 0;

  // Truncate very long summaries
  const summary = originalLength > MAX_SUMMARY_LENGTH 
    ? s.summary.substring(0, MAX_SUMMARY_LENGTH) 
    : s.summary;

  return {
    id: s.article_id || s.id,  // Use article_id as primary, fallback to id
    title: `Summary ${index + 1}`,  // Summaries don't have titles
    body: summary,  // Use summary as body for LLM
    language: s.language || 'en',
    source: 'article_summary',
    published_at: s.processed_at || new Date().toISOString(),
    summary_truncated: originalLength > MAX_SUMMARY_LENGTH,
    original_summary_length: originalLength
  };
});

console.log(`📊 Processing ${processed.length} article summaries`);
console.log(`📏 Avg summary length: ${Math.round(processed.reduce((sum, p) => sum + p.body.length, 0) / processed.length)} chars`);

return processed.map(a => ({ json: a }));

const items = $input.all().map(i => i.json);
const pad2 = n => String(n).padStart(2, '0');
const pad3 = n => String(n).padStart(3, '0');
const now = new Date();
const datePart = `${now.getFullYear()}-${pad2(now.getMonth()+1)}-${pad2(now.getDate())}_${pad2(now.getHours())}${pad2(now.getMinutes())}`;
const requestId = `n8n_webhook_${datePart}_${pad3($runIndex+1)}`;

// Get filter data from earlier node
const filterData = $('Parse Webhook Request').first().json;
const filters = filterData?.filters || {};
const options = filterData?.options || {};

// Get cluster info from Extract Article IDs node
const extractData = $('Extract Article IDs').first().json;
const clusterInfo = extractData?.cluster_info || [];

const articleIds = items.map(a => a.id).filter(Boolean);
const articles = items.map(a => ({
  id: a.id || "",
  url: "",
  title: a.title || "",
  body: a.body || "",
  language: a.language || "en",
  source: a.source || "",
  published_at: a.published_at || new Date().toISOString(),
  category: "general"
}));

if (articles.length > 100) throw new Error(`Too many: ${articles.length}`);
if (articles.length === 0) throw new Error('No articles');

console.log(`✅ WEBHOOK BATCH ${$runIndex + 1}: ${articles.length} articles from ${extractData?.cluster_count || 0} clusters`);

return [{
  json: {
    llm_payload: {
      request_id: requestId,
      filters_used: filters,
      articles: articles
    },
    llm_batch_record: {
      request_id: requestId,
      filters_used: filters,
      options: options,
      article_ids: articleIds,
      article_count: articles.length,
      source_cluster_count: extractData?.cluster_count || 0,
      source_clusters: clusterInfo,
      status: "pending",
      ingested_at: new Date().toISOString(),
      trigger_type: "webhook",
      llm_endpoint: "/cluster_summary",
      output_index: "batch_summaries"
    }
  }
}];

// FORMAT BATCH SUMMARIES - FINAL SOLUTION
// This completely ignores LLM article responses and uses original articles

const resp = $json;
const request_id = resp.request_id || "";
const clusters = resp.clusters || [];

// Get the ORIGINAL articles that were sent to LLM
const prepareBatchData = $('Prepare Batch').first().json;
const originalArticles = prepareBatchData?.llm_payload?.articles || [];

console.log(`\n${'='.repeat(80)}`);
console.log(`📋 FORMAT BATCH SUMMARIES`);
console.log(`${'='.repeat(80)}`);
console.log(`Request ID: ${request_id}`);
console.log(`Clusters from LLM: ${clusters.length}`);
console.log(`Original articles from Prepare Batch: ${originalArticles.length}`);

// Strategy: Evenly distribute the original articles across all clusters
// This way we keep the LLM's summaries but use the correct articles
const articlesPerCluster = Math.ceil(originalArticles.length / clusters.length);

const enrichedClusters = clusters.map((cluster, idx) => {
  // Calculate which original articles belong to this cluster
  const startIdx = idx * articlesPerCluster;
  const endIdx = Math.min(startIdx + articlesPerCluster, originalArticles.length);
  const clusterArticles = originalArticles.slice(startIdx, endIdx);

  console.log(`Cluster ${cluster.cluster_id}: ${clusterArticles.length} articles (${startIdx} to ${endIdx-1})`);

  return {
    cluster_id: cluster.cluster_id,
    category: cluster.category || "Events",
    subcategory: cluster.subcategory || "",
    topic_summary: cluster.topic_summary || "",
    articles: clusterArticles,  // ← Use ORIGINAL articles, not LLM's
    article_count: clusterArticles.length,
    keywords: cluster.keywords || { lda: [], tfidf: [] }
  };
});

// IMPORTANT: Use only the FIRST cluster's summary to avoid duplication
// All clusters have the same summary anyway
const final_summary = enrichedClusters.length > 0 && enrichedClusters[0].topic_summary
  ? enrichedClusters[0].topic_summary
  : "No summary available";

console.log(`Final summary length: ${final_summary.length} chars`);
console.log(`Total clusters: ${enrichedClusters.length}`);
console.log(`Total articles distributed: ${enrichedClusters.reduce((sum, c) => sum + c.article_count, 0)}`);
console.log(`${'='.repeat(80)}\n`);

return [{
  json: {
    _source: {
      request_id: request_id,
      summary_type: "cluster_summary",
      cluster_count: enrichedClusters.length,
      clusters: enrichedClusters,
      final_summary: final_summary,
      final_summary_keyword: "cluster_summary",
      ingested_at: new Date().toISOString()
    },
    processing_time: resp.processing_time || 0
  }
}];

const batchData = $('Prepare Batch').first().json.llm_batch_record;
const llmResponse = $('Call cluster_summary').first().json;

return [{
  json: {
    request_id: batchData.request_id,
    update: {
      ...batchData,
      status: "completed",
      processed_at: new Date().toISOString(),
      processing_time: llmResponse.processing_time || 0,
      cluster_count: llmResponse.cluster_count || 0,
      clusters_generated: llmResponse.clusters?.length || 0
    }
  }
}];

const allSummaries = [];
const loopResults = $('Format batch_summaries').all();

loopResults.forEach(item => {
  const summary = item.json._source;
  allSummaries.push({
    request_id: summary.request_id,
    summary: summary.final_summary,
    cluster_count: summary.cluster_count,
    clusters: summary.clusters,
    ingested_at: summary.ingested_at
  });
});

// FIXED: Don't duplicate - just use the first summary (they're all the same topic)
// The final_summary already contains all cluster summaries joined together
const combinedSummary = allSummaries.length > 0 
  ? allSummaries[0].summary 
  : "";

// Get all clusters and deduplicate by cluster_id
const allClustersRaw = allSummaries.flatMap(s => s.clusters || []);

// FIXED: Deduplicate clusters by cluster_id
const clusterMap = new Map();
allClustersRaw.forEach(cluster => {
  const key = `${cluster.cluster_id}`;
  if (!clusterMap.has(key)) {
    clusterMap.set(key, cluster);
  }
});
const allClusters = Array.from(clusterMap.values());

console.log(`📊 Total clusters after deduplication: ${allClusters.length}`);
console.log(`📊 Total batches processed: ${allSummaries.length}`);

// Count total unique articles across all clusters
let totalArticles = 0;
const articleIdSet = new Set();

allClusters.forEach(cluster => {
  const articles = cluster.articles || [];
  articles.forEach(article => {
    // Use title + body as unique identifier (since IDs might be missing)
    const articleKey = `${article.title}_${article.source}_${article.published_at}`;
    articleIdSet.add(articleKey);
  });
  totalArticles += articles.length;
});

console.log(`📊 Total article references: ${totalArticles}`);
console.log(`📊 Unique articles: ${articleIdSet.size}`);

// Get original filters
const parseData = $('Parse Webhook Request').first().json;
const extractData = $('Extract Article IDs').first().json;
const filters = parseData?.filters || {};

return [{
  json: {
    success: true,
    batches_processed: allSummaries.length,
    filters_applied: filters,
    source_clusters: extractData?.cluster_count || 0,
    cluster_info: extractData?.cluster_info || [],
    total_article_clusters: allClusters.length,
    total_unique_articles: articleIdSet.size,
    final_summary: combinedSummary,
    individual_summaries: allSummaries,
    all_clusters: allClusters,
    processed_at: new Date().toISOString()
  }
}];

const data = $json;
const articleIds = data.article_ids;
const filters = data.filters || {};

// If no article IDs and cluster filter was used, return error
if (filters.use_cluster_filter && (!articleIds || articleIds.length === 0)) {
  console.log('⚠️ No article IDs from clusters - no matching clusters found');

  // Return a query that will find nothing
  const emptyQuery = {
    size: 0,
    _source: ['article_id'],
    query: {
      bool: {
        must: [
          { term: { "article_id": "NO_CLUSTERS_FOUND" }}
        ]
      }
    }
  };

  return [{
    json: {
      opensearch_query: emptyQuery,
      filters: filters,
      options: data.options,
      no_clusters_found: true
    }
  }];
}

let query;
if (articleIds && articleIds.length > 0) {
  console.log(`🎯 Fetching ${articleIds.length} article summaries by ID from clusters`);

  // Build base query with article IDs
  const must = [
    { terms: { "article_id": articleIds }}
  ];

  // Build query for article_summaries index
  query = {
    size: filters.size || 1000,
    _source: ['article_id', 'id', 'summary', 'language', 'processed_at'],
    query: {
      bool: {
        must: must
      }
    },
    sort: [
      { processed_at: { order: "desc" }}
    ]
  };
} else {
  // Fallback: direct article filtering (not using clusters)
  console.log('🔍 No cluster filter - using direct article query');

  const must = [];

  // Time filter
  if (filters.time_window) {
    const now = new Date();
    let gte;
    switch(filters.time_window.toLowerCase()) {
      case 'last_6_hours':
        gte = new Date(now.getTime() - 6*60*60*1000);
        break;
      case 'last_12_hours':
        gte = new Date(now.getTime() - 12*60*60*1000);
        break;
      case 'last_24_hours':
        gte = new Date(now.getTime() - 24*60*60*1000);
        break;
      case 'last_3_days':
        gte = new Date(now.getTime() - 3*24*60*60*1000);
        break;
      case 'last_7_days':
        gte = new Date(now.getTime() - 7*24*60*60*1000);
        break;
    }
    if (gte) {
      must.push({ range: { processed_at: { gte: gte.toISOString() }}});
    }
  }

  // Keywords filter
  if (filters.keywords && filters.keywords.length > 0) {
    must.push({
      bool: {
        should: filters.keywords.map(k => ({
          match: {
            summary: k
          }
        }))
      }
    });
  }

  query = {
    size: filters.size || 1000,
    _source: ['article_id', 'id', 'summary', 'language', 'processed_at'],
    query: {
      bool: {
        must: must.length > 0 ? must : [{ match_all: {} }]
      }
    },
    sort: [
      { processed_at: { order: "desc" }}
    ]
  };
}

console.log(`📋 Final query: ${JSON.stringify(query, null, 2)}`);

return [{
  json: {
    opensearch_query: query,
    filters: filters,
    options: data.options
  }
}];

// This runs when Prepare Articles errors
const error = $json.error || {};
const errorMessage = error.message || "Unknown error";

console.log(`❌ Error caught: ${errorMessage}`);

// Parse the error type
let userMessage = "No results found";
let errorType = "UNKNOWN";

if (errorMessage.includes('NO_CLUSTERS_FOUND')) {
  errorType = "NO_CLUSTERS_FOUND";
  userMessage = "No clusters matched your search criteria. Try different filters or categories.";
} else if (errorMessage.includes('NO_ARTICLES_FOUND')) {
  errorType = "NO_ARTICLES_FOUND";
  userMessage = "No articles found for the selected clusters. The articles may have been removed.";
} else if (errorMessage.includes('NO_VALID_ARTICLES')) {
  errorType = "NO_VALID_ARTICLES";
  userMessage = "Articles found but all are missing content.";
}

const parseData = $('Parse Webhook Request').first().json;
const filters = parseData?.filters || {};

return [{
  json: {
    success: false,
    error_type: errorType,
    message: userMessage,
    batches_processed: 0,
    filters_applied: filters,
    source_clusters: 0,
    final_summary: "",
    processed_at: new Date().toISOString()
  }
}];

const hits = $json.hits?.hits ?? [];

// Check if this was a "no clusters found" case


if (hits.length === 0) {
  console.log('⚠️ No articles found matching the query - throwing error');
  throw new Error('NO_ARTICLES_FOUND: No articles found for the selected clusters. The articles may have been removed from the index.');
}

const articles = hits.map(h => h._source).filter(a => a && a.body);

if (articles.length === 0) {
  console.log('⚠️ No valid articles (all missing body) - throwing error');
  throw new Error('NO_VALID_ARTICLES: Articles found but all are missing content.');
}

const MAX_BODY_LENGTH = 10000;
const processed = articles.map(a => {
  if (a.body && a.body.length > MAX_BODY_LENGTH) {
    return { ...a, body: a.body.substring(0, MAX_BODY_LENGTH), body_truncated: true };
  }
  return { ...a, body_truncated: false };
});

console.log(`📊 Processing ${processed.length} articles`);
return processed.map(a => ({ json: a }));
